let current: ThreadPtr = pre_self_.get_cpu(cpu_id).current_thread.unwrap();
let owning_ct: ContainerPtr = pre_self_.get_thread(current).owning_container;

if post1_self_.wf()
    && post2_self_.wf()
    && (post1_self_.page_closure() =~= pre_self_.page_closure())
    && (post2_self_.page_closure() =~= pre_self_.page_closure())
    && (post1_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post2_self_.proc_dom() =~= pre_self_.proc_dom())
    && (post1_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post2_self_.endpoint_dom() == pre_self_.endpoint_dom())
    && (post1_self_.container_dom() == pre_self_.container_dom())
    && (post2_self_.container_dom() == pre_self_.container_dom())
    && (post1_self_.thread_dom() == pre_self_.thread_dom())
    && (post2_self_.thread_dom() == pre_self_.thread_dom())
    && (forall|p_ptr: ProcPtr|
        #![trigger post1_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==> post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|p_ptr: ProcPtr|
        #![trigger post2_self_.get_proc(p_ptr)]
        pre_self_.proc_dom().contains(p_ptr) ==> post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post1_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr) && container_ptr != owning_ct
            ==> post1_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|container_ptr: ContainerPtr|
        #![trigger post2_self_.get_container(container_ptr)]
        pre_self_.container_dom().contains(container_ptr) && container_ptr != owning_ct
            ==> post2_self_.get_container(container_ptr) =~= pre_self_.get_container(container_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != current
            ==> pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr))
    && (forall|t_ptr: ThreadPtr|
        #![trigger pre_self_.get_thread(t_ptr)]
        pre_self_.thread_dom().contains(t_ptr) && t_ptr != current
            ==> pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post1_self_.get_endpoint(e_ptr)]
        post1_self_.endpoint_dom().contains(e_ptr) ==> pre_self_.get_endpoint(e_ptr)
            =~= post1_self_.get_endpoint(e_ptr))
    && (forall|e_ptr: EndpointPtr|
        #![trigger post2_self_.get_endpoint(e_ptr)]
        post2_self_.endpoint_dom().contains(e_ptr) ==> pre_self_.get_endpoint(e_ptr)
            =~= post2_self_.get_endpoint(e_ptr))
    && (forall|cpu_i: CpuId|
        #![trigger post1_self_.get_cpu(cpu_i)]
        0 <= cpu_i < NUM_CPUS && cpu_i != cpu_id ==> pre_self_.get_cpu(cpu_i) == post1_self_.get_cpu(cpu_i))
    && (forall|cpu_i: CpuId|
        #![trigger post2_self_.get_cpu(cpu_i)]
        0 <= cpu_i < NUM_CPUS && cpu_i != cpu_id ==> pre_self_.get_cpu(cpu_i) == post2_self_.get_cpu(cpu_i))
    && (post1_self_.get_thread(current).owning_container == pre_self_.get_thread(current).owning_container)
    && (post2_self_.get_thread(current).owning_container == pre_self_.get_thread(current).owning_container)
    && (post1_self_.get_thread(current).owning_proc == pre_self_.get_thread(current).owning_proc)
    && (post2_self_.get_thread(current).owning_proc == pre_self_.get_thread(current).owning_proc)
    && post1_self_.get_thread(current).blocking_endpoint_ptr.is_None()
    && post2_self_.get_thread(current).blocking_endpoint_ptr.is_None()
    && post1_self_.get_thread(current).blocking_endpoint_index.is_None()
    && post2_self_.get_thread(current).blocking_endpoint_index.is_None()
    && (post1_self_.get_thread(current).endpoint_descriptors == pre_self_.get_thread(current).endpoint_descriptors)
    && (post2_self_.get_thread(current).endpoint_descriptors == pre_self_.get_thread(current).endpoint_descriptors)
    && post1_self_.get_thread(current).running_cpu.is_None()
    && post2_self_.get_thread(current).running_cpu.is_None()
    && (post1_self_.get_thread(current).state == ThreadState::SCHEDULED)
    && (post2_self_.get_thread(current).state == ThreadState::SCHEDULED)
    && (post1_self_.get_thread(current).ipc_payload == IPCPayLoad::Empty)
    && (post2_self_.get_thread(current).ipc_payload == IPCPayLoad::Empty)
    && post1_self_.get_thread(current).error_code.is_None()
    && post2_self_.get_thread(current).error_code.is_None()
    && post1_self_.get_thread(current).trap_frame.is_Some()
    && post2_self_.get_thread(current).trap_frame.is_Some()
    && (post1_self_.get_thread(current).trap_frame.unwrap() == *pt_regs)
    && (post2_self_.get_thread(current).trap_frame.unwrap() == *pt_regs)
    && (post1_self_.get_container(owning_ct).parent == pre_self_.get_container(owning_ct).parent)
    && (post2_self_.get_container(owning_ct).parent == pre_self_.get_container(owning_ct).parent)
    && (post1_self_.get_container(owning_ct).children == pre_self_.get_container(owning_ct).children)
    && (post2_self_.get_container(owning_ct).children == pre_self_.get_container(owning_ct).children)
    && (post1_self_.get_container(owning_ct).depth == pre_self_.get_container(owning_ct).depth)
    && (post2_self_.get_container(owning_ct).depth == pre_self_.get_container(owning_ct).depth)
    && (post1_self_.get_container(owning_ct).uppertree_seq == pre_self_.get_container(owning_ct).uppertree_seq)
    && (post2_self_.get_container(owning_ct).uppertree_seq == pre_self_.get_container(owning_ct).uppertree_seq)
    && (post1_self_.get_container(owning_ct).subtree_set == pre_self_.get_container(owning_ct).subtree_set)
    && (post2_self_.get_container(owning_ct).subtree_set == pre_self_.get_container(owning_ct).subtree_set)
    && (post1_self_.get_container(owning_ct).root_process == pre_self_.get_container(owning_ct).root_process)
    && (post2_self_.get_container(owning_ct).root_process == pre_self_.get_container(owning_ct).root_process)
    && (post1_self_.get_container(owning_ct).owned_procs == pre_self_.get_container(owning_ct).owned_procs)
    && (post2_self_.get_container(owning_ct).owned_procs == pre_self_.get_container(owning_ct).owned_procs)
    && (post1_self_.get_container(owning_ct).owned_endpoints == pre_self_.get_container(owning_ct).owned_endpoints)
    && (post2_self_.get_container(owning_ct).owned_endpoints == pre_self_.get_container(owning_ct).owned_endpoints)
    && (post1_self_.get_container(owning_ct).owned_threads == pre_self_.get_container(owning_ct).owned_threads)
    && (post2_self_.get_container(owning_ct).owned_threads == pre_self_.get_container(owning_ct).owned_threads)
    && (post1_self_.get_container(owning_ct).quota == pre_self_.get_container(owning_ct).quota)
    && (post2_self_.get_container(owning_ct).quota == pre_self_.get_container(owning_ct).quota)
    && (post1_self_.get_container(owning_ct).owned_cpus == pre_self_.get_container(owning_ct).owned_cpus)
    && (post2_self_.get_container(owning_ct).owned_cpus == pre_self_.get_container(owning_ct).owned_cpus)
    && (post1_self_.get_container(owning_ct).can_have_children == pre_self_.get_container(owning_ct).can_have_children)
    && (post2_self_.get_container(owning_ct).can_have_children == pre_self_.get_container(owning_ct).can_have_children)
    && (post1_self_.get_container(owning_ct).scheduler@ == pre_self_.get_container(owning_ct).scheduler@.push(current))
    && (post2_self_.get_container(owning_ct).scheduler@ == pre_self_.get_container(owning_ct).scheduler@.push(current))
    && (post1_self_.get_cpu(cpu_id).owning_container == pre_self_.get_cpu(cpu_id).owning_container)
    && (post2_self_.get_cpu(cpu_id).owning_container == pre_self_.get_cpu(cpu_id).owning_container)
    && (post1_self_.get_cpu(cpu_id).active == pre_self_.get_cpu(cpu_id).active)
    && (post2_self_.get_cpu(cpu_id).active == pre_self_.get_cpu(cpu_id).active)
    && post1_self_.get_cpu(cpu_id).current_thread.is_None()
    && post2_self_.get_cpu(cpu_id).current_thread.is_None()
{
    // --- cpu_list@ pointwise equality ---
    // Cpu = { owning_container, active, current_thread }, all three pinned at cpu_id,
    // and get_cpu(cpu_i) == pre.get_cpu(cpu_i) for cpu_i != cpu_id.
    assert(post1_self_.cpu_list@.len() == NUM_CPUS) by {
        assert(post1_self_.get_cpu(cpu_id) == post1_self_.cpu_list@[cpu_id as int]);
    };
    assert(post2_self_.cpu_list@.len() == NUM_CPUS) by {
        assert(post2_self_.get_cpu(cpu_id) == post2_self_.cpu_list@[cpu_id as int]);
    };
    assert(pre_self_.cpu_list@.len() == NUM_CPUS) by {
        assert(pre_self_.get_cpu(cpu_id) == pre_self_.cpu_list@[cpu_id as int]);
    };
    assert forall|i: int| 0 <= i < post1_self_.cpu_list@.len()
        implies post1_self_.cpu_list@[i] == post2_self_.cpu_list@[i]
    by {
        let ci: CpuId = i as CpuId;
        assert(0 <= ci < NUM_CPUS);
        if ci == cpu_id {
            assert(post1_self_.get_cpu(cpu_id).owning_container
                == post2_self_.get_cpu(cpu_id).owning_container);
            assert(post1_self_.get_cpu(cpu_id).active
                == post2_self_.get_cpu(cpu_id).active);
            assert(post1_self_.get_cpu(cpu_id).current_thread
                == post2_self_.get_cpu(cpu_id).current_thread);
            assert(post1_self_.get_cpu(cpu_id) =~= post2_self_.get_cpu(cpu_id));
            assert(post1_self_.cpu_list@[i] == post1_self_.get_cpu(ci));
            assert(post2_self_.cpu_list@[i] == post2_self_.get_cpu(ci));
        } else {
            assert(pre_self_.get_cpu(ci) == post1_self_.get_cpu(ci));
            assert(pre_self_.get_cpu(ci) == post2_self_.get_cpu(ci));
            assert(post1_self_.cpu_list@[i] == post1_self_.get_cpu(ci));
            assert(post2_self_.cpu_list@[i] == post2_self_.get_cpu(ci));
        }
    };
    assert(post1_self_.cpu_list@ =~= post2_self_.cpu_list@);

    // --- domain extensionality for the four perm maps ---
    assert(post1_self_.container_perms@.dom() =~= post2_self_.container_perms@.dom());
    assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
    assert(post1_self_.thread_perms@.dom() =~= post2_self_.thread_perms@.dom());
    assert(post1_self_.endpoint_perms@.dom() =~= post2_self_.endpoint_perms@.dom());

    // --- process_perms pointwise PointsTo equality ---
    assert forall|p_ptr: ProcPtr|
        post1_self_.process_perms@.dom().contains(p_ptr)
        implies post1_self_.process_perms@[p_ptr] == post2_self_.process_perms@[p_ptr]
    by {
        assert(pre_self_.proc_dom().contains(p_ptr));
        assert(post1_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post2_self_.get_proc(p_ptr) =~= pre_self_.get_proc(p_ptr));
        assert(post1_self_.process_perms@[p_ptr].value()
            =~= post2_self_.process_perms@[p_ptr].value());
        assert(post1_self_.process_perms@[p_ptr].addr() == p_ptr);
        assert(post2_self_.process_perms@[p_ptr].addr() == p_ptr);
        assert(post1_self_.process_perms@[p_ptr].is_init());
        assert(post2_self_.process_perms@[p_ptr].is_init());
        assert(post1_self_.process_perms@[p_ptr]
            =~= post2_self_.process_perms@[p_ptr]);
    };
    assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);

    // --- container_perms pointwise PointsTo equality ---
    assert forall|c_ptr: ContainerPtr|
        post1_self_.container_perms@.dom().contains(c_ptr)
        implies post1_self_.container_perms@[c_ptr] == post2_self_.container_perms@[c_ptr]
    by {
        assert(pre_self_.container_dom().contains(c_ptr));
        if c_ptr != owning_ct {
            assert(post1_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post2_self_.get_container(c_ptr) =~= pre_self_.get_container(c_ptr));
            assert(post1_self_.container_perms@[c_ptr].value()
                =~= post2_self_.container_perms@[c_ptr].value());
        } else {
            // At owning_ct, all listed Container fields are pinned to pre's,
            // and scheduler@ is the same push of current on both sides.
            assert(post1_self_.get_container(owning_ct).parent
                == post2_self_.get_container(owning_ct).parent);
            assert(post1_self_.get_container(owning_ct).children
                == post2_self_.get_container(owning_ct).children);
            assert(post1_self_.get_container(owning_ct).depth
                == post2_self_.get_container(owning_ct).depth);
            assert(post1_self_.get_container(owning_ct).uppertree_seq
                == post2_self_.get_container(owning_ct).uppertree_seq);
            assert(post1_self_.get_container(owning_ct).subtree_set
                == post2_self_.get_container(owning_ct).subtree_set);
            assert(post1_self_.get_container(owning_ct).root_process
                == post2_self_.get_container(owning_ct).root_process);
            assert(post1_self_.get_container(owning_ct).owned_procs
                == post2_self_.get_container(owning_ct).owned_procs);
            assert(post1_self_.get_container(owning_ct).owned_endpoints
                == post2_self_.get_container(owning_ct).owned_endpoints);
            assert(post1_self_.get_container(owning_ct).owned_threads
                == post2_self_.get_container(owning_ct).owned_threads);
            assert(post1_self_.get_container(owning_ct).quota
                == post2_self_.get_container(owning_ct).quota);
            assert(post1_self_.get_container(owning_ct).owned_cpus
                == post2_self_.get_container(owning_ct).owned_cpus);
            assert(post1_self_.get_container(owning_ct).can_have_children
                == post2_self_.get_container(owning_ct).can_have_children);
            assert(post1_self_.get_container(owning_ct).scheduler@
                == post2_self_.get_container(owning_ct).scheduler@);
            // We can pin every field of Container EXCEPT parent_rev_ptr and the
            // scheduler StaticLinkedList's internal nodes — but the listed ensures
            // do not constrain those. Still, force value extensional equality:
            assert(post1_self_.get_container(owning_ct) =~= post2_self_.get_container(owning_ct));
            assert(post1_self_.container_perms@[c_ptr].value()
                =~= post2_self_.container_perms@[c_ptr].value());
        }
        assert(post1_self_.container_perms@[c_ptr].addr() == c_ptr);
        assert(post2_self_.container_perms@[c_ptr].addr() == c_ptr);
        assert(post1_self_.container_perms@[c_ptr].is_init());
        assert(post2_self_.container_perms@[c_ptr].is_init());
        assert(post1_self_.container_perms@[c_ptr]
            =~= post2_self_.container_perms@[c_ptr]);
    };
    assert(post1_self_.container_perms@ =~= post2_self_.container_perms@);

    // --- thread_perms pointwise PointsTo equality ---
    assert forall|t_ptr: ThreadPtr|
        post1_self_.thread_perms@.dom().contains(t_ptr)
        implies post1_self_.thread_perms@[t_ptr] == post2_self_.thread_perms@[t_ptr]
    by {
        assert(pre_self_.thread_dom().contains(t_ptr));
        if t_ptr != current {
            assert(pre_self_.get_thread(t_ptr) =~= post1_self_.get_thread(t_ptr));
            assert(pre_self_.get_thread(t_ptr) =~= post2_self_.get_thread(t_ptr));
            assert(post1_self_.thread_perms@[t_ptr].value()
                =~= post2_self_.thread_perms@[t_ptr].value());
        } else {
            // At current, fields constrained: owning_container, owning_proc,
            // blocking_endpoint_ptr, blocking_endpoint_index, endpoint_descriptors,
            // running_cpu, state, ipc_payload, error_code, trap_frame.
            // Not constrained: proc_rev_ptr, scheduler_rev_ptr, endpoint_rev_ptr.
            assert(post1_self_.get_thread(current).owning_container
                == post2_self_.get_thread(current).owning_container);
            assert(post1_self_.get_thread(current).owning_proc
                == post2_self_.get_thread(current).owning_proc);
            assert(post1_self_.get_thread(current).blocking_endpoint_ptr
                == post2_self_.get_thread(current).blocking_endpoint_ptr);
            assert(post1_self_.get_thread(current).blocking_endpoint_index
                == post2_self_.get_thread(current).blocking_endpoint_index);
            assert(post1_self_.get_thread(current).endpoint_descriptors
                == post2_self_.get_thread(current).endpoint_descriptors);
            assert(post1_self_.get_thread(current).running_cpu
                == post2_self_.get_thread(current).running_cpu);
            assert(post1_self_.get_thread(current).state
                == post2_self_.get_thread(current).state);
            assert(post1_self_.get_thread(current).ipc_payload
                == post2_self_.get_thread(current).ipc_payload);
            assert(post1_self_.get_thread(current).error_code
                == post2_self_.get_thread(current).error_code);
            assert(post1_self_.get_thread(current).trap_frame
                == post2_self_.get_thread(current).trap_frame);
            assert(post1_self_.get_thread(current) =~= post2_self_.get_thread(current));
            assert(post1_self_.thread_perms@[t_ptr].value()
                =~= post2_self_.thread_perms@[t_ptr].value());
        }
        assert(post1_self_.thread_perms@[t_ptr].addr() == t_ptr);
        assert(post2_self_.thread_perms@[t_ptr].addr() == t_ptr);
        assert(post1_self_.thread_perms@[t_ptr].is_init());
        assert(post2_self_.thread_perms@[t_ptr].is_init());
        assert(post1_self_.thread_perms@[t_ptr]
            =~= post2_self_.thread_perms@[t_ptr]);
    };
    assert(post1_self_.thread_perms@ =~= post2_self_.thread_perms@);

    // --- endpoint_perms pointwise PointsTo equality ---
    assert forall|e_ptr: EndpointPtr|
        post1_self_.endpoint_perms@.dom().contains(e_ptr)
        implies post1_self_.endpoint_perms@[e_ptr] == post2_self_.endpoint_perms@[e_ptr]
    by {
        assert(post1_self_.endpoint_dom().contains(e_ptr));
        assert(post2_self_.endpoint_dom().contains(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post1_self_.get_endpoint(e_ptr));
        assert(pre_self_.get_endpoint(e_ptr) =~= post2_self_.get_endpoint(e_ptr));
        assert(post1_self_.endpoint_perms@[e_ptr].value()
            =~= post2_self_.endpoint_perms@[e_ptr].value());
        assert(post1_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
        assert(post2_self_.endpoint_perms@[e_ptr].addr() == e_ptr);
        assert(post1_self_.endpoint_perms@[e_ptr].is_init());
        assert(post2_self_.endpoint_perms@[e_ptr].is_init());
        assert(post1_self_.endpoint_perms@[e_ptr]
            =~= post2_self_.endpoint_perms@[e_ptr]);
    };
    assert(post1_self_.endpoint_perms@ =~= post2_self_.endpoint_perms@);

    // --- root_container: this isn't constrained by any ensures, but the wf()
    // invariants likely pin it implicitly via internal_wf. Force it via =~=. ---
    assert(post1_self_.root_container == post2_self_.root_container);

    // --- r1 == r2 (unit type) ---
    assert(r1 == r2);

    // --- Final: det predicate holds. ---
    assert(det_schedule_running_thread_equal(r1, r2, post1_self_, post2_self_));
}
